{
  "document_background": {
    "page_sections": [
      {
        "source_section": "集團首席執行官兼總裁報告",
        "target_section": "Group Chief Executive and President's Report",
        "content_type": "ceo_report",
        "page_range": [
          12,
          16
        ]
      }
    ],
    "roles": [
      {
        "source": "李源祥",
        "target": "Lee Yuen Cheung",
        "role": "Group Chief Executive and President"
      }
    ],
    "terms": [],
    "style_rules": [
      "Use US$ for U.S. dollar amounts.",
      "Keep listed-company annual report disclosure tone formal and publishable.",
      "Do not change numbers, percentages, years, named entities or financial metric values.",
      "For overview narrative, use full financial metric name plus abbreviation when provided.",
      "For financial review and business metrics narrative, use established abbreviations when provided.",
      "Prefer AIA China / AIA Hong Kong / AIA Macau over loose paraphrases when matched."
    ]
  },
  "current_unit": {
    "page_no": 16,
    "unit_id": "p16_g04",
    "unit_mode": "semantic_group",
    "slot_count": 4,
    "source_text": "我對友邦保險的長遠未來前景充滿信心。儘管面對短期不明朗因素，但帶動需求的本土因素強勁，加上亞洲的主\n要人口結構趨勢，仍為友邦保險業務的長遠前景提供正面的結構性支持。在大眾收入增加、私人保險滲透率偏\n低，以及社會福利覆蓋有限的情況下，市場對友邦保險產品的需求將繼續增長。我們將憑藉龐大的競爭優勢和強\n勁的增長往績，為社區創建更可持續的未來，並為所有持分者創造共享價值。",
    "current_translation": "I am confident about AIA's long-term prospects. Despite near-term uncertainties, strong domestic drivers of demand, coupled with key demographic trends across Asia, continue to provide positive structural support for AIA's long-term business outlook. With rising incomes, low private insurance penetration, and limited social welfare coverage, demand for AIA's products will continue to grow. Leveraging our substantial competitive advantages and strong track record of growth, we will build a more sustainable future for our communities and create shared value for all our stakeholders."
  },
  "output_format": {
    "translations": [
      {
        "unit_id": "p16_g04",
        "translation": "<更紧凑译文>"
      }
    ]
  }
}

